SELECT ?county ?countyLabel (COUNT(?player) AS ?count) WHERE {
  ?player wdt:P166 wd:Q4729678;
          wdt:P485 ?county.
  ?county rdfs:label ?countyLabel.
  FILTER(LANG(?countyLabel) = 'en')
} GROUP BY ?county ?countyLabel HAVING (COUNT(?player) >= 2) ORDER BY DESC(?count)

